#include<bits/stdc++.h>
using namespace std;

bool pime(int x){
    for(int i=2;i*i<=x;i++) if(x%i==0) return 0;
    return 1;
}

int main(){
    int n;
    cin>>n;
    for(int i=4;i<=n;i+=2){ for(int j=2;j<=i;j++) {if(pime(j)){ if(pime(i-j)) {printf("%d=%d+%d\n",i,j,i-j);break;}}}}


    return 0;
}
